#!/bin/bash

# LINE Rich Menu Deployment Helper
# Usage: bash deploy-rich-menu.sh <menu_type> <domain>
# Example: bash deploy-rich-menu.sh employee https://tdone-erp.com

MENU_TYPE=${1:-employee}
DOMAIN=${2:-https://localhost:3000}
SESSION_TOKEN=${3}

if [ -z "$SESSION_TOKEN" ]; then
  echo "❌ Error: SESSION_TOKEN is required"
  echo "Usage: bash deploy-rich-menu.sh <menu_type> <domain> <session_token>"
  echo "Example:"
  echo "  bash deploy-rich-menu.sh employee https://tdone-erp.com YOUR_SESSION_TOKEN"
  exit 1
fi

echo "📋 Deploying $MENU_TYPE Rich Menu to $DOMAIN"

# Employee menu - 2 rows x 3 columns
if [ "$MENU_TYPE" = "employee" ]; then
  PAYLOAD=$(cat <<EOF
{
  "action": "create_and_set_default",
  "imageContentType": "image/svg+xml",
  "imageBase64": "",
  "richMenu": {
    "size": {
      "width": 2500,
      "height": 1686
    },
    "selected": true,
    "name": "TD One Employee Menu",
    "chatBarText": "TD One ERP",
    "areas": [
      {
        "bounds": {
          "x": 0,
          "y": 0,
          "width": 833,
          "height": 843
        },
        "action": {
          "type": "uri",
          "uri": "$DOMAIN/dashboard"
        }
      },
      {
        "bounds": {
          "x": 833,
          "y": 0,
          "width": 833,
          "height": 843
        },
        "action": {
          "type": "uri",
          "uri": "$DOMAIN/scan"
        }
      },
      {
        "bounds": {
          "x": 1666,
          "y": 0,
          "width": 834,
          "height": 843
        },
        "action": {
          "type": "uri",
          "uri": "$DOMAIN/slip"
        }
      },
      {
        "bounds": {
          "x": 0,
          "y": 843,
          "width": 833,
          "height": 843
        },
        "action": {
          "type": "uri",
          "uri": "$DOMAIN/request/leave"
        }
      },
      {
        "bounds": {
          "x": 833,
          "y": 843,
          "width": 833,
          "height": 843
        },
        "action": {
          "type": "uri",
          "uri": "$DOMAIN/request/ot"
        }
      },
      {
        "bounds": {
          "x": 1666,
          "y": 843,
          "width": 834,
          "height": 843
        },
        "action": {
          "type": "uri",
          "uri": "$DOMAIN/request/time-correction"
        }
      }
    ]
  }
}
EOF
)
else
  PAYLOAD=$(cat <<EOF
{
  "action": "create_and_set_default",
  "imageContentType": "image/svg+xml",
  "imageBase64": "",
    "richMenu": {
      "size": {
        "width": 2500,
        "height": 843
      },
      "selected": true,
      "name": "TD One Admin Menu",
      "chatBarText": "TD One Admin",
      "areas": [
        {
          "bounds": {
            "x": 0,
            "y": 0,
            "width": 625,
            "height": 843
          },
          "action": {
            "type": "uri",
            "uri": "$DOMAIN/dashboard"
          }
        },
        {
          "bounds": {
            "x": 625,
            "y": 0,
            "width": 625,
            "height": 843
          },
          "action": {
            "type": "uri",
            "uri": "$DOMAIN/attendance"
          }
        },
        {
          "bounds": {
            "x": 1250,
            "y": 0,
            "width": 625,
            "height": 843
          },
          "action": {
            "type": "uri",
            "uri": "$DOMAIN/payroll"
          }
        },
        {
          "bounds": {
            "x": 1875,
            "y": 0,
            "width": 625,
            "height": 843
          },
          "action": {
            "type": "uri",
            "uri": "$DOMAIN/admin/pin-reset-audit"
          }
        }
      ]
    }
  }
}
EOF
)
fi

echo "📤 Sending request to $DOMAIN/api/line/rich-menu..."

curl -X POST "$DOMAIN/api/line/rich-menu" \
  -H "Authorization: Bearer $SESSION_TOKEN" \
  -H "Content-Type: application/json" \
  -d "$PAYLOAD"

echo ""
echo "✅ Done!"
